#include &lt;unistd.h&gt;
#include &lt;sys/socket.h&gt;
#include &lt;netinet/in.h&gt;

int main() {
    // 1. Create the listening socket (Layer 3: IPv4, Layer 4: TCP)
    int server_fd = socket(AF_INET, SOCK_STREAM, 0);

    // (Setup address struct here - see Topic 3)
    struct sockaddr_in addr = {0};
    addr.sin_family = AF_INET;
    addr.sin_port = htons(8080);
    addr.sin_addr.s_addr = INADDR_ANY;

    // 2. Bind the socket to port 8080
    if (bind(server_fd, (struct sockaddr*)&addr, sizeof(addr)) < 0) {
        perror("Bind failed"); return 1;
    }

    // 3. Enter Passive Listening state
    listen(server_fd, 10);
    printf("Server listening on port 8080...\n");

    // 4. The Infinite Accept Loop
    while (1) {
        // Thread blocks here until someone completes the Layer 4 handshake
        int client_fd = accept(server_fd, NULL, NULL);
        printf("Client connected!\n");

        char buffer[1024];
        ssize_t bytes = read(client_fd, buffer, sizeof(buffer));
        if (bytes > 0) {
            // Echo the bytes back to the client
            write(client_fd, buffer, bytes);
        }

        // Disconnect this specific client.
        // The server_fd remains open for the next loop iteration.
        close(client_fd);
    }
    return 0;
}

